import SectionHeader from './SectionHeader';

const jobs = [
  { date:'Sep 2025 · On-site', role:'Banking Intern', co:'Commercial International Bank (CIB) · Asyut', desc:'Selected for branch internship based on outstanding online performance. Hands-on experience in banking operations and customer service.' },
  { date:'Jul 2025 · 2 Weeks', role:'Industrial Intern', co:'Asyut Oil Refining Co. (ASORC) · Asyut', desc:'Trained in petroleum refining operations, industrial safety, and collaborated with senior engineers.' },
  { date:'Aug 2024 · 2 Weeks', role:'Marketing Intern', co:'Nile Petroleum Marketing Co. · Asyut', desc:'Blended theoretical + practical marketing training with a cross-functional team.' },
];

const trainings = [
  { icon:'🏦', iconBg:'bg-amber/10', org:'CIB × SAS × Udemy', name:'Online Training Program', date:'Aug 2025 — Trustworthy AI · Customer Centricity · Sustainability' },
  { icon:'🌐', iconBg:'bg-teal/10', org:'Banque Misr × Google', name:'Maharat Digital Marketing', date:'Jul 2025 — Digital Marketing Fundamentals' },
  { icon:'💼', iconBg:'bg-soft-blue/10', org:'HSBC × Forage', name:'Digital Business Services Sim', date:'Oct 2024 — Sustainability · Project Management' },
];

export default function Experience() {
  return (
    <section id="experience" className="py-24 px-[5%] bg-cream">
      <SectionHeader tag="Career" title='Experience & <em class="italic text-teal not-italic font-serif-display">Training</em>' />
      <div className="grid md:grid-cols-2 gap-16">

        {/* Timeline */}
        <div className="reveal delay-1 relative pl-7">
          <div className="absolute left-0 top-1.5 bottom-4 w-[1.5px] bg-gradient-to-b from-amber via-teal to-transparent rounded-full" />
          {jobs.map((j, i) => (
            <div key={i} className="relative pb-9 last:pb-0 group">
              <div className="absolute -left-7 top-1.5 w-2.5 h-2.5 rounded-full bg-parchment border-[2.5px] border-amber -translate-x-[4px] transition-all group-hover:bg-amber" />
              <p className="text-[.68rem] font-semibold tracking-wider uppercase text-amber mb-1">{j.date}</p>
              <h3 className="font-serif-display text-lg tracking-tight mb-0.5">{j.role}</h3>
              <p className="text-xs text-muted font-medium mb-2">{j.co}</p>
              <p className="text-[.87rem] leading-[1.75] text-muted2">{j.desc}</p>
            </div>
          ))}
        </div>

        {/* Training cards */}
        <div className="reveal delay-2 flex flex-col gap-3">
          {trainings.map((t, i) => (
            <div key={i} className="flex gap-3 items-start bg-parchment rounded-xl px-5 py-4 border-[1.5px] border-transparent shadow-sm transition-all hover:border-teal/20 hover:-translate-y-0.5 hover:shadow-md">
              <div className={`w-9 h-9 ${t.iconBg} rounded-lg flex items-center justify-center text-base flex-shrink-0`}>{t.icon}</div>
              <div>
                <p className="text-[.62rem] font-semibold tracking-wider uppercase text-teal mb-1">{t.org}</p>
                <p className="font-semibold text-[.9rem] text-ink2">{t.name}</p>
                <p className="text-[.72rem] text-muted mt-0.5">{t.date}</p>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}
